class Solution:
    def countWinningSequences(self, s: str) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [[[0]*3 for _ in range(3)] for _ in range(n+1)]
        dp[0][0][0] = 1
        for i in range(n):
            for j in range(3):
                for k in range(3):
                    if dp[i][j][k] == 0:
                        continue
                    for l in range(3):
                        if l == j:
                            continue
                        if (s[i] == 'F' and l == 2) or (s[i] == 'W' and l == 0) or (s[i] == 'E' and l == 1):
                            dp[i+1][l][k] = (dp[i+1][l][k] + dp[i][j][k]) % MOD
                        else:
                            dp[i+1][l][j] = (dp[i+1][l][j] + dp[i][j][k]) % MOD
        res = 0
        for i in range(3):
            for j in range(3):
                res = (res + dp[n][i][j]) % MOD
        return res
